/* eslint-disable */
import Docxtemplater from 'docxtemplater';
import PizZip from 'pizzip'; // Reemplazo de JSZip en este ecosistema

// Asumiendo que usted tiene un método para cargar el archivo de plantilla (template.docx) como un ArrayBuffer
// Por ejemplo, cargándolo previamente o usando un fetch:
async function loadTemplate(url) {
    const response = await fetch(url);
    if (!response.ok) {
        throw new Error(`Error al cargar la plantilla: ${response.statusText}`);
    }
    return response.arrayBuffer();
}

export async function generateWordDocument(documentData, procedureData) {
    // 1. Cargar el ArrayBuffer de su plantilla (debe subirla o tenerla en su proyecto)
    // Cambie 'ruta/a/su/template.docx' a la ubicación correcta
    const templateContent = await loadTemplate('ruta/a/su/template.docx');

    // 2. Crear una instancia de PizZip con el contenido de la plantilla
    const zip = new PizZip(templateContent);

    // 3. Inicializar Docxtemplater
    const doc = new Docxtemplater(zip, {
        paragraphLoop: true, // Importante para que las listas/tablas funcionen bien
        linebreaks: true     // Para manejar saltos de línea dentro del texto
    });

    // 4. Transformar sus datos al formato esperado por la plantilla
    const payload = {
        // Datos del encabezado
        codigo: documentData.headerConfig?.codigo || 'XX-P-XXX-#',
        manualName: documentData.headerConfig?.manualName || 'Manual de Políticas y Procedimientos',
        area: documentData.headerConfig?.area || 'Área responsable',
        revision: documentData.headerConfig?.revision || '(1)',
        // Secciones (Docxtemplater maneja bien el texto plano)
        objetivo: documentData.objetivo || 'Contenido pendiente de completar.',
        alcance: documentData.alcance || 'Contenido pendiente de completar.',
        // ... otras secciones ...

        // Datos de la tabla (Docxtemplater usará el nombre de la variable 'procedimiento')
        procedimiento: procedureData.map(row => ({
            number: String(row.number || '').trim(),
            who: String(row.who || '').trim(),
            // Docxtemplater se encarga de escapar el XML de este campo
            activity: String(row.activity || '').trim(), 
            level: row.level
            // Nota: El formato de nivel (colores) es más complejo de manejar en Docxtemplater
            // sin plugins avanzados, pero la estructura de la tabla y los datos funcionarán.
        }))
    };
    
    // 5. Establecer los datos y generar el documento
    doc.setData(payload);
    
    try {
        doc.render();
    } catch (error) {
        // Manejo de errores de renderizado (p.ej. si falta un campo en los datos)
        throw new Error(`Error de Docxtemplater: ${error.message}`);
    }

    // 6. Generar el Blob y descargarlo (similar a su código actual)
    const out = doc.getZip().generate({
        type: 'blob',
        mimeType: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        compression: 'DEFLATE'
    });

    const fileName = `${documentData.headerConfig?.policyName || 'Procedimiento'}.docx`;
    
    // Lógica de descarga (puede usar su código de descarga anterior)
    if (window.navigator && window.navigator.msSaveOrOpenBlob) {
        window.navigator.msSaveOrOpenBlob(out, fileName);
    } else {
        const url = URL.createObjectURL(out);
        const link = document.createElement('a');
        link.href = url;
        link.download = fileName;
        link.click();
        URL.revokeObjectURL(url);
    }
}
